private preferencesService?: PreferencesService;
private historyService?: NotificationHistoryService;
private sendQueue: Promise<void> = Promise.resolve();

async sendNotification(params: {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  priority: NotificationPriority;
  metadata?: Record<string, unknown>;
}): Promise<Notification> {
  // Chain onto the send queue to guarantee delivery order.
  // Without this, concurrent events (e.g., order:created and
  // order:status-changed emitted in quick succession) can have
  // their async adapter.send() calls resolve out of order.
  let resolve!: (n: Notification) => void;
  let reject!: (err: unknown) => void;
  const resultPromise = new Promise<Notification>((res, rej) => {
    resolve = res;
    reject = rej;
  });

  this.sendQueue = this.sendQueue.then(async () => {
    try {
      const notification = await this.processNotification(params);
      resolve(notification);
    } catch (err) {
      reject(err);
    }
  });

  return resultPromise;
}

/**
 * Internal: process a single notification (preference check, adapter dispatch, logging).
 */
private async processNotification(params: {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  priority: NotificationPriority;
  metadata?: Record<string, unknown>;
}): Promise<Notification> {
  // Check user preferences before sending
  if (this.preferencesService) {
    const shouldSend = this.preferencesService.shouldSendNotification(
      params.recipient,
      params.channel,
      params.type,
    );
    if (!shouldSend) {
      this.logger.info(
        `Notification suppressed by user preferences: ${params.type} to ${params.recipient} via ${params.channel}`,
      );
      const suppressedNotification: Notification = {
        id: generateNotificationId(),
        type: params.type,
        channel: params.channel,
        recipient: params.recipient,
        subject: params.subject,
        body: params.body,
        priority: params.priority,
        delivered: false,
        error: 'Suppressed by user preferences',
        createdAt: new Date(),
      };
      this.notifications.push(suppressedNotification);
      this.historyService?.logNotification(suppressedNotification);
      return suppressedNotification;
    }
  }

  const payload: NotificationPayload = {
    id: generateNotificationId(),
    type: params.type,
    channel: params.channel,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    priority: params.priority,
    createdAt: new Date(),
    metadata: params.metadata,
  };

  const adapter = this.adapters.get(params.channel);
  let notification: Notification;

  if (adapter) {
    const result = await adapter.send(payload);
    notification = {
      id: payload.id,
      type: payload.type,
      channel: payload.channel,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      priority: payload.priority,
      delivered: result.success,
      error: result.error,
      createdAt: payload.createdAt,
      deliveredAt: result.deliveredAt,
    };
  } else {
    this.logger.warn(`No adapter registered for channel: ${params.channel}`);
    notification = {
      id: payload.id,
      type: payload.type,
      channel: payload.channel,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      priority: payload.priority,
      delivered: false,
      error: `No adapter registered for channel: ${params.channel}`,
      createdAt: payload.createdAt,
    };
  }

  this.notifications.push(notification);
  this.historyService?.logNotification(notification);
  this.logger.info(`Notification ${notification.id} to ${params.recipient}: delivered=${notification.delivered}`);
  return notification;
}

